const body = $('Webhook').first().json.body ?? $('Webhook').first().json;

const toolCallId =
  body.toolCallId ||
  body.message?.toolCallId ||
  body.message?.toolCallList?.[0]?.id ||
  body.message?.toolWithToolCallList?.[0]?.toolCall?.id ||
  "";

// try to get raw text from likely places
const rawText =
  body.message?.content ||
  body.message?.text ||
  body.transcript ||
  body.input ||
  JSON.stringify(body);

// helper
const match = (regex) => {
  const m = rawText.match(regex);
  return m ? m[1].trim() : "";
};

const customerName =
  match(/my name is\s+([A-Za-z]+(?:\s+[A-Za-z]+)+)/i) ||
  match(/name[:\s]+([A-Za-z]+(?:\s+[A-Za-z]+)+)/i);

const phone =
  match(/phone number is\s+(\d{11,15})/i) ||
  match(/number is\s+(\d{11,15})/i) ||
  match(/phone[:\s]+(\d{11,15})/i);

const email =
  match(/email is\s+([A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,})/i) ||
  match(/email[:\s]+([A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,})/i);

const orderType =
  /pickup/i.test(rawText) ? "Pickup" : "Delivery";

const items =
  match(/order for\s+(.+?)(?:\.\s*the total is|\.\s*deliver to|\.\s*i want|\.$)/i) ||
  match(/please place an order for\s+(.+?)(?:\.\s*the total is|\.\s*deliver to|\.$)/i);

const total =
  match(/total is\s+([\d,]+)\s*naira/i) ||
  match(/total comes to\s+[\₦N]?([\d,]+)/i);

const address =
  match(/deliver to\s+(.+?)(?:\s+at\s+\d|\.$)/i) ||
  match(/address is\s+(.+?)(?:\.\s|$)/i);

const deliveryTime =
  match(/at\s+([0-9]{1,2}(?::[0-9]{2})?\s*(?:am|pm))/i);

return [
  {
    json: {
      OrderID: 'ORD' + Date.now(),
      CustomerName: customerName,
      Phone: phone,
      Email: email,
      OrderType: orderType,
      Items: items,
      Total: total,
      Address: address,
      Status: 'Pending',
      DeliveryTime: deliveryTime,
      toolCallId
    }
  }
];

const original = $('Code in JavaScript').first().json;
const toolCallId = original.toolCallId || "";

return [
  {
    json: {
      results: [
        {
          toolCallId: String(toolCallId),
          result: "Order placed successfully and saved in the system."
        }
      ]
    }
  }
];
